```python
class HashTable:
    def __init__(self, size=64):
        self.size = size
        self.buckets = [[] for _ in range(size)]

    def _hash(self, key):
        return hash(key) % self.size

    def set(self, key, value):
        bucket = self.buckets[self._hash(key)]
        for i, (k, v) in enumerate(bucket):
            if k == key:
                bucket[i] = (key, value)  # Update
                return
        bucket.append((key, value))  # Insert

    def get(self, key, default=None):
        bucket = self.buckets[self._hash(key)]
        for k, v in bucket:
            if k == key: return v
        return default

    def delete(self, key):
        bucket = self.buckets[self._hash(key)]
        self.buckets[self._hash(key)] = [
            (k, v) for k, v in bucket if k != key
        ]

ht = HashTable()
ht.set('name', 'Alice')
print(ht.get('name'))  # Alice
```
Chaining handles collisions. Load factor = items/buckets. Rehash when > 0.75.

Dijkstra's algorithm finds shortest path from source to all nodes (non-negative weights). O((V+E) log V).

```python
import heapq

def dijkstra(graph, start):
    # graph = {node: [(neighbor, weight), ...]}
    dist = {node: float('inf') for node in graph}
    dist[start] = 0
    pq = [(0, start)]  # (distance, node)

    while pq:
        d, node = heapq.heappop(pq)
        if d > dist[node]: continue  # Outdated entry

        for neighbor, weight in graph[node]:
            new_dist = dist[node] + weight
            if new_dist < dist[neighbor]:
                dist[neighbor] = new_dist
                heapq.heappush(pq, (new_dist, neighbor))

    return dist

graph = {
    'A': [('B', 4), ('C', 2)],
    'B': [('D', 3), ('C', 1)],
    'C': [('B', 1), ('D', 5)],
    'D': []
}
print(dijkstra(graph, 'A'))  # {'A': 0, 'B': 3, 'C': 2, 'D': 6}
```
For unweighted graphs: use BFS. For negative weights: Bellman-Ford.

Find two indices in array that add to target.

```python
# Brute force O(n²)
def two_sum_brute(nums, target):
    for i in range(len(nums)):
        for j in range(i+1, len(nums)):
            if nums[i] + nums[j] == target:
                return [i, j]

# Hash map O(n) time, O(n) space
def two_sum(nums, target):
    seen = {}  # value → index
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return [seen[complement], i]
        seen[num] = i
    return []

print(two_sum([2, 7, 11, 15], 9))  # [0, 1]
print(two_sum([3, 2, 4], 6))       # [1, 2]
```
Key insight: for each number, check if its complement (target - num) already exists. Hash map gives O(1) lookup. Classic interview problem — also check sorted two-pointer approach for sorted arrays.
